  * the legal folder of your Openbravo installation.
  * Software distributed under the License is distributed on an
  * "AS IS" basis, WITHOUT WARRANTY OF ANY KIND, either express or
  * implied. See the License for the specific language governing rights
  * and limitations under the License.
  * The Original Code is  Compiere  ERP  Solution
  * The Initial Developer of the Original Code is Jorg Janke and ComPiere, Inc.
  * Portions created by Jorg Janke are Copyright (C) 1999-2001 Jorg Janke,
  * parts created by ComPiere are Copyright (C) ComPiere, Inc.;
  * All Rights Reserved.
  * Contributor(s): Rodney Jacome
  * Contributions are Copyright (C) 2001-2011 Openbravo, S.L.U.
  *
  * Specifically, this derivative work is based upon the following Compiere
  * file and version.

  ************************************************************************/
    -- Logistic
    v_ResultStr VARCHAR2(2000):='';
    v_Message VARCHAR2(2000):='';
    v_Record_ID VARCHAR2(32);

    -- Parameter
    -- Audit
    v_AD_Client_ID VARCHAR2(32);
    v_AD_ORG_ID VARCHAR2(32);
    v_AD_USER_ID VARCHAR2(32);
    TYPE RECORD IS REF CURSOR;
    Cur_Parameter RECORD;
    Cur_fin_payment RECORD;
    Cur_sum_payment RECORD;

    -- Parameter Variables
    v_sspch_invoice_id VARCHAR2(32);
    v_c_invoice_id VARCHAR2(32);
    v_fin_payment_schedule_id VARCHAR2(32);
    v_c_doctype_id VARCHAR2(32);
    v_sspch_payment_plan_id VARCHAR2(32);
    v_ssfi_banktransfer_id VARCHAR2(32);
    v_account VARCHAR2(200);
    v_account_holder VARCHAR2(200);
    v_paymet_date DATE;
    v_outstandingamt NUMBER:=0;
    v_sum_outstandingamt NUMBER:=0;
    v_check_up NUMBER:=0;
    v_check_from NUMBER:=0;
    v_shareno NUMBER:=0;
    v_sum_shareno NUMBER:=0;
    v_shareno_resp NUMBER:=0;
    v_advance_value NUMBER:=0;
    v_quota_value NUMBER:=0;
    v_amount_payment NUMBER:=0;
    v_total_checks NUMBER:=0;
    v_resp_payment_amt NUMBER:=0;
    v_resp_amt NUMBER:=0;
    v_count NUMBER:=0;
    v_count_resp NUMBER:=0;
    v_resp_T_amt NUMBER:=0;
    v_checkno_advanced NUMBER:=0;
    v_check_advanced_resp NUMBER:=0;
    v_quota_value_resp NUMBER:=0;
    v_checkno_quota_value NUMBER:=0;
    v_insert_lines NUMBER:=0;
    v_NoOfFields NUMBER:=0;
    v_enought_amount NUMBER:=0;
    v_shareno_order NUMBER:=0;
    v_trl_count NUMBER;
    v_NextNo_F VARCHAR2(32);
	v_general_payment_date DATE;
    v_payment_day NUMBER;
    v_payment_month NUMBER;
    -- Copy
    Cur_Fields RECORD;
    Row_Src_Field AD_Field%ROWTYPE;
    Row_Dest_Field_Trl AD_Field_Trl%ROWTYPE;

    v_field_name NVARCHAR2(60);
    v_field_desc NVARCHAR2(255);
    v_field_help NVARCHAR2(2000);
    assigned BOOLEAN;

  BEGIN
    --  Update AD_PInstance
    DBMS_OUTPUT.PUT_LINE('Updating PInstance - Processing ' || p_PInstance_ID) ;
    v_ResultStr:='PInstanceNotFound';
    AD_UPDATE_PINSTANCE(p_PInstance_ID, NULL, 'Y', NULL, NULL) ;
  BEGIN --BODY
    -- Get Parameters
    v_ResultStr:='ReadingParameters';
    FOR Cur_Parameter IN
      (SELECT i.Record_ID, i.ad_user_id, i.ad_org_id, i.ad_client_id
      FROM AD_PInstance i
      WHERE i.AD_PInstance_ID=p_PInstance_ID
      )
    LOOP
      v_Record_ID := Cur_Parameter.Record_ID;
      v_AD_Client_ID := Cur_Parameter.ad_client_id;
      v_AD_ORG_ID := Cur_Parameter.ad_org_id;
      v_AD_USER_ID := Cur_Parameter.ad_user_id;
    END LOOP; -- Get Parameter
    DBMS_OUTPUT.PUT_LINE('  Record_ID=' || v_Record_ID) ;
    v_ResultStr:='GetEntityType';

	--HEAD VAR
	Select 	to_number(spc.check_up)	, to_number(spc.check_from)	,total_checks		, ad_org_id	, ssfi_banktransfer_id		, account	, account_holder
			,payment_day
		Into v_check_up		, v_check_from			,v_total_checks		, v_AD_ORG_ID	, v_ssfi_banktransfer_id	, v_account	, v_account_holder
			,v_payment_day
	From sspch_postdated_checks spc
	Where spc.sspch_postdated_checks_id = v_Record_ID;


    -- Record_ID is the Tab_ID to copy to
    v_ResultStr:='Copying';
    v_field_help:='';
	-- CURSOR AGRUPADOR DE CUOTAS
	FOR Cur_sum_payment IN (
		Select 	gg.shareno
			, SUM(gg.outstandingamt) as outstandingamt
			, count(*) as count
		From (Select 
				row_number() over (partition by si.c_invoice_id  order by coalesce(fps.em_ssppi_shareno,1) ) as shareno
				, (fps.outstandingamt-coalesce(sfp.amount,0)) as "outstandingamt"
			From sspch_invoice  si  
				join c_invoice i on si.c_invoice_id = i.c_invoice_id
				join fin_payment_schedule fps on fps.c_invoice_id = i.c_invoice_id
				Left Join (Select SUM(COALESCE(fpsd.amount,0)) as "amount"
							, fpsd.fin_payment_schedule_invoice as "fin_payment_schedule_id"
						From fin_payment_scheduledetail fpsd 
							Join fin_payment_detail fpd on fpd.fin_payment_detail_id = fpsd.fin_payment_detail_id 
							Join fin_payment fp on fp.fin_payment_id = fpd.fin_payment_id
						Where fp.status = 'RPAE'-- A Ejecutar
						Group By fpsd.fin_payment_schedule_invoice) sfp on sfp.fin_payment_schedule_id = fps.fin_payment_schedule_id
			Where  sspch_postdated_checks_id = v_Record_ID 
				AND (fps.outstandingamt-coalesce(sfp.amount,0)) > 0
				AND EXISTS (Select 1
					From fin_payment_scheduledetail fpsd
					where fpsd.fin_payment_schedule_invoice = fps.fin_payment_schedule_id
						And fpsd.isinvoicepaid = 'N' --cuotas con saldo pendiente
						And em_sspch_postdated_checks_id is null)
		) gg 
		Group By gg.shareno
		Order BY gg.shareno ASC
	)LOOP
		--VARIABLES DE AGRUPADOR
		v_sum_outstandingamt 	:= Cur_sum_payment.outstandingamt;
		v_sum_shareno		:= Cur_sum_payment.shareno;
		v_count			:= Cur_sum_payment.count;
		v_resp_T_amt 		:= v_total_checks / v_count;
		v_resp_amt		:=0;
		--CURSOR DE CUOTAS ORDENADAS POR CUOTAS Y VALOR ACENDENTE
		FOR Cur_fin_payment IN (
			select * 
			From (
				Select i.c_invoice_id
					, sspch_invoice_id
					, i.c_doctype_id
					, si.c_invoice_id
					, i.documentno
					, fps.duedate 
					, fps.fin_payment_schedule_id
					, coalesce(fps.em_ssppi_shareno,1) as shareno
					, row_number() over (partition by si.c_invoice_id  order by coalesce(fps.em_ssppi_shareno,1) ) as shareno_order
					, fps.outstandingamt-coalesce(sfp.amount,0) as "outstandingamt"
				From sspch_invoice  si  
					join c_invoice i on si.c_invoice_id = i.c_invoice_id
					join fin_payment_schedule fps on fps.c_invoice_id = i.c_invoice_id
					Left Join (Select SUM(COALESCE(fpsd.amount,0)) as "amount"
							, fpsd.fin_payment_schedule_invoice as "fin_payment_schedule_id"
						From fin_payment_scheduledetail fpsd 
							Join fin_payment_detail fpd on fpd.fin_payment_detail_id = fpsd.fin_payment_detail_id 
							Join fin_payment fp on fp.fin_payment_id = fpd.fin_payment_id
						Where fp.status = 'RPAE'-- A Ejecutar
						Group By fpsd.fin_payment_schedule_invoice) sfp on sfp.fin_payment_schedule_id = fps.fin_payment_schedule_id
				Where  sspch_postdated_checks_id = v_Record_ID
					And fps.outstandingamt-coalesce(sfp.amount,0) > 0
					AND EXISTS (
					Select 1
					From fin_payment_scheduledetail fpsd
					where fpsd.fin_payment_schedule_invoice = fps.fin_payment_schedule_id
						And fpsd.isinvoicepaid = 'N' --cuotas con saldo pendiente
						And em_sspch_postdated_checks_id is null
					)
			) gg
			where gg.shareno_order = v_sum_shareno
			Order By gg.shareno_order ,gg.outstandingamt ASC	
		)LOOP
			--VARIABLES PARA PLAN DE PAGOS
			v_insert_lines			:=v_insert_lines+1;
			v_sspch_invoice_id 		:= Cur_fin_payment.sspch_invoice_id ;
			v_fin_payment_schedule_id 	:= Cur_fin_payment.fin_payment_schedule_id ;
			v_amount_payment 		:= Cur_fin_payment.outstandingamt ;
			v_shareno 			:= Cur_fin_payment.shareno ;
			v_shareno_order			:= Cur_fin_payment.shareno_order ;--3
			v_c_doctype_id			:= Cur_fin_payment.c_doctype_id ;
			v_paymet_date			:= Cur_fin_payment.duedate ;
			v_sspch_payment_plan_id		:= get_uuid() ;
			v_advance_value 		:= 0 ;
			v_c_invoice_id			:= Cur_fin_payment.c_invoice_id;

			-- CONDICIONES PARA SECUENCIA DE NUMERO DE CHEQUE(POR NUMERO DE CUOTA)
			If( v_shareno_resp = 0 )Then
				v_shareno_resp:=v_shareno_order; 
			ELSE 
				If(v_shareno_resp<>v_shareno_order AND v_check_from IS NOT NULL)Then
					v_check_from 	:= v_check_from + 1; 
					v_shareno_resp 	:= v_shareno_order;
				End If;
			End IF;

			-- CONDICIONES SEGUN EL DIA DE COBRO DE LA CABECERA
			IF ( v_payment_day is not null AND v_payment_day > 0) THEN
				SELECT extract(month FROM v_paymet_date::date) INTO v_payment_month;
				IF (v_payment_day > 28 AND v_payment_month=2) THEN
					v_general_payment_date := ('28/'||TO_CHAR(v_paymet_date::date,'MM/yyyy'))::date;
				ELSIF (v_payment_day = 31 AND v_payment_month  in (4,6,9,11))	THEN
					v_general_payment_date := ('30/'||TO_CHAR(v_paymet_date::date,'MM/yyyy'))::date;
				ELSE 
					v_general_payment_date := (v_payment_day||'/'||TO_CHAR(v_paymet_date::date,'MM/yyyy'))::date;
				END IF;
			ELSE 
				v_general_payment_date := v_paymet_date;
			END IF;

			-- VALIDACION PARA LIMITES DE CHEQUES
			If(v_check_from>v_check_up OR v_check_from IS NULL)
				Then	v_check_from		:= NULL;
				Else	v_checkno_advanced	:= v_check_from;
			End IF;

			--VALIDACIONES PARA VALOR DE CUOTA Y VALOR DE ANTICIPO
			If (v_check_from Is not null) Then
				v_resp_payment_amt 	:= v_resp_T_amt + v_resp_amt;
				v_resp_amt		:=0;

				-- valor de la cuota es mayor a el valor dividido por lineas más sobrantes anteriores
				IF(v_amount_payment > v_resp_payment_amt)
					Then
						--Si el valor calculado para la cuota no tiene sobrantes sumados
						If (v_resp_payment_amt = v_resp_T_amt)Then
							v_quota_value 		:= v_resp_payment_amt; 	-- Valor que le corresponde
						Else
							If(v_count_resp = 0)Then
								v_count_resp := v_count;
							End IF;
							v_quota_value 		:= v_resp_T_amt; 	
							v_quota_value_resp 	:= v_quota_value_resp+(v_resp_payment_amt-v_resp_T_amt);
							v_resp_amt		:= 0;
							v_checkno_quota_value	:=v_check_from;
						End IF;
					Else	v_quota_value	:= v_amount_payment;	-- Valor igual correspondiente
						v_resp_amt	:= v_resp_payment_amt - v_amount_payment; -- Valor sobrante
				End If;
			ELSE
				v_resp_amt		:= 0;
				v_quota_value		:= 0;	
				If(v_total_checks <> 0)Then
					v_enought_amount := 1;
				End IF;
			End IF;

			-- INSERTAR EN PLAN DE PAGOS
			INSERT INTO sspch_payment_plan (
				sspch_payment_plan_id		, ad_client_id			, ad_org_id			, createdby		, updatedby
				, sspch_invoice_id		, c_doctype_id			, documentno 			, quota_value		, shareno				
				, payment_date			, fin_payment_schedule_id	, checkno			, amount_payment	, isadvance			
				, advance_value			, sspch_postdated_checks_id	, c_invoice_id			, ssfi_banktransfer_id	, account	
				, account_holder		, general_payment_date)
			VALUES (  v_sspch_payment_plan_id	, v_AD_Client_ID		, v_AD_ORG_ID			, v_AD_USER_ID		, v_AD_USER_ID
				, v_sspch_invoice_id		, v_c_doctype_id		, Cur_fin_payment.documentno	, v_quota_value		, v_shareno			
				, v_paymet_date			, v_fin_payment_schedule_id	, v_check_from			, v_amount_payment 	, 'N'				
				, v_advance_value		, v_Record_ID			, v_c_invoice_id		, v_ssfi_banktransfer_id, v_account	
				, v_account_holder		, v_general_payment_date);

			v_count:=v_count-1;

		END Loop; -- END Cur_fin_payment

		-- CONSUMIR VALOR DE TOTAL PARA CHEQUES(HEAD)	
		If(v_enought_amount = 0)THEN
			If(v_total_checks - v_sum_outstandingamt>0)
				Then 	v_total_checks	:= v_total_checks - v_sum_outstandingamt ;
				Else 	v_total_checks	:= 0;
			End IF;		
		End If;		
		-- ACTUALIZAR PROPORCIONALMENTE EL VALOR DE CUOTA SOBRANTE[Solo si no dispone valor suficiente para ultimo cheque]
		If(v_quota_value_resp>0)Then

			v_quota_value 	:= v_quota_value_resp / v_count_resp;
			Update sspch_payment_plan set  
					quota_value = quota_value + v_quota_value
				Where round(quota_value,5) = round(v_resp_T_amt,5)
					AND to_number(checkno)  = v_checkno_quota_value 
					And sspch_invoice_id  in(Select si.sspch_invoice_id 
								From sspch_invoice si 
								Where si.sspch_postdated_checks_id = v_Record_ID);
		End IF ;
	END Loop; -- END Cur_sum_payment

	-- ACTUALIZAR VALOR DEL ANTICIPO DE MANERA PROPORCIONAL AL ULTIMO CHEQUE
	If(v_check_advanced_resp > 0 OR v_total_checks>0)Then

		Select COUNT(*) 
			Into v_count_resp
		From sspch_payment_plan
		Where to_number(checkno)  = v_checkno_advanced 
			And sspch_invoice_id  in (Select si.sspch_invoice_id 
				From sspch_invoice si 
				Where si.sspch_postdated_checks_id = v_Record_ID);

		v_advance_value	:=ROUND(((v_check_advanced_resp+v_total_checks)/v_count_resp),5);

		Update sspch_payment_plan set  
				isadvance ='Y'	
				, advance_value=v_advance_value
		Where to_number(checkno)  = v_checkno_advanced 
			And sspch_invoice_id  in (Select si.sspch_invoice_id 
					From sspch_invoice si 
					Where si.sspch_postdated_checks_id = v_Record_ID);
	End IF;

    v_Message:='@RowsInserted@=' || v_insert_lines ;
    --<<FINISH_PROCESS>>

    --  Update AD_PInstance
    DBMS_OUTPUT.PUT_LINE('Updating PInstance - Finished ' || v_Message) ;
    AD_UPDATE_PINSTANCE(p_PInstance_ID, NULL, 'N', 1, v_Message) ;
   RETURN;
  END; --BODY
EXCEPTION
WHEN OTHERS THEN
  v_ResultStr:= '@ERROR=' || SQLERRM;
  DBMS_OUTPUT.PUT_LINE(v_ResultStr) ;
  AD_UPDATE_PINSTANCE(p_PInstance_ID, NULL, 'N', 0, v_ResultStr) ;
  RETURN;
END SSPCH_LOAD_LINES
